// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect, useRef, useCallback } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'
import { Calendar, QrCode, Edit2, Trash2, Box, Check } from 'lucide-react'
import DatePicker from 'react-datepicker'
import { subDays } from 'date-fns'
import Etiqueta from './Etiqueta'
import { QRCodeSVG as QRCode } from 'qrcode.react'

export default function TelaEsterilizacao() {
  // Wizard
  const [step, setStep] = useState(1)
  const [operation, setOperation] = useState(null) // 'entrada' ou 'saida'

  // Dados
  const [codigo, setCodigo] = useState('')
  const [allCaixas, setAllCaixas] = useState([])
  const [caixas, setCaixas] = useState([])
  const [alunoPin, setAlunoPin] = useState('')
  const [alunoNome, setAlunoNome] = useState('')
  const [pinValidated, setPinValidated] = useState(false)
  const [historico, setHistorico] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [filterDate, setFilterDate] = useState('')
  const [printData, setPrintData] = useState(null)
  const [printedBoxes, setPrintedBoxes] = useState([]) // para marcar impressos

  const datePickerRef = useRef(null)
  const componentRef = useRef(null)
  const storedUser = JSON.parse(localStorage.getItem('user') || '{}')
  const usuarioLogadoNome = storedUser.nome || ''

  const BADGE_STYLES = [
    'bg-blue-100 text-blue-800',
    'bg-green-100 text-green-800',
    'bg-yellow-100 text-yellow-800',
    'bg-purple-100 text-purple-800',
  ]

  // Impressão em nova janela
  useEffect(() => {
    if (!printData) return
    const area = document.getElementById('area-impressao')
    if (!area) return
    const html = `
      <html><head><title>Etiqueta</title>
      <style>body{margin:0;padding:8mm;font-family:sans-serif}</style>
      </head><body>${area.innerHTML}</body></html>`
    const w = window.open('', '_blank', 'width=600,height=400')
    w.document.write(html); w.document.close(); w.focus(); w.print()
    setPrintData(null); setTimeout(() => w.close(), 500)
  }, [printData])

  // Carrega caixas
  useEffect(() => {
    axios.get('/api/caixas')
      .then(r => setAllCaixas(r.data))
      .catch(() => setAllCaixas([]))
  }, [])

  // Busca histórico
  const fetchHistory = useCallback(() => {
    if (!pinValidated || !alunoNome) return
    axios.get('/api/movimentacoes')
      .then(r => {
        const hoje = new Date()
        const from = subDays(hoje,30).toISOString().slice(0,10)
        const to = hoje.toISOString().slice(0,10)
        const fil = r.data.filter(m => {
          const d = new Date(m.criado_em).toISOString().slice(0,10)
          return m.alunoNome===alunoNome && d>=from && d<=to
        })
        setHistorico(fil)
      })
      .catch(() => setHistorico([]))
  }, [alunoNome,pinValidated])
  useEffect(() => { fetchHistory() }, [fetchHistory])

  // Sugestões
  const suggestions = codigo
    ? allCaixas.filter(c =>
        c.nome.toLowerCase().includes(codigo.toLowerCase()) ||
        c.codigo_barras.includes(codigo)
      ).slice(0,5)
    : []

  const addCaixa = c => {
    setCaixas(prev => [...prev,c])
    toast.success(`Caixa adicionada: ${c.nome}`,{autoClose:5000})
    setCodigo('')
  }
  const buscarCaixa = () => {
    const e = allCaixas.find(c=>
      c.codigo_barras===codigo||c.nome.toLowerCase().includes(codigo.toLowerCase())
    )
    if(!e){ toast.error('Caixa não encontrada',{autoClose:5000}); return }
    addCaixa(e)
  }

  // Valida PIN
  const validarPin = () => {
    if(alunoPin.trim().length!==4){
      toast.warn('PIN deve ter 4 dígitos',{autoClose:5000}); return
    }
    axios.get(`/api/alunos/pin/${alunoPin}`)
      .then(r => {
        setAlunoNome(r.data.nome)
        setPinValidated(true)
        toast.success(`PIN validado: ${r.data.nome}`,{autoClose:5000})
        fetchHistory()
        setStep(3)
      })
      .catch(()=>toast.error('Aluno não encontrado',{autoClose:5000}))
  }

  // Executa operação
  const operar = async tipo => {
    if(!pinValidated){
      toast.warn('Valide o PIN',{autoClose:5000}); return
    }
    if(caixas.length===0){
      toast.warn('Adicione ao menos uma caixa',{autoClose:5000}); return
    }
    if(tipo==='saida'){
      const inv = caixas.filter(c=>{
        const h = historico.filter(m=>m.caixa_id===c.id)
        return !h.length||h[0].tipo!=='entrada'
      })
      if(inv.length){
        inv.forEach(c=>toast.error(`Caixa "${c.nome}" sem entrada`,{autoClose:5000}))
        return
      }
    }
    try{
      await Promise.all(caixas.map(c=>
        axios.post(`/api/movimentacoes/${tipo}`,{
          caixa_id:c.id,aluno_pin:alunoPin
        })
      ))
      toast.success(`${tipo==='entrada'?'Entrada':'Saída'} registrada!`,{autoClose:5000})
      // reset completo
      setCaixas([]); setAlunoPin(''); setAlunoNome(''); setPinValidated(false)
      setOperation(null); setHistorico([]); setSearchTerm(''); setFilterDate('')
      setStep(1); setPrintedBoxes([])
    }catch{
      toast.error(`Erro ao registrar ${tipo}`,{autoClose:5000})
    }
  }

  // Prepara impressão + marca impresso
  const handlePrint = c => {
    setPrintData({
      alunoNome,
      caixaId: c.id,
      caixaNome: c.nome,
      criadoEm: c.criado_em||new Date().toISOString(),
      recebidoPor: usuarioLogadoNome,
    })
    setPrintedBoxes(prev=> prev.includes(c.id) ? prev : [...prev,c.id])
  }

  const removerCaixa = id => setCaixas(prev=>prev.filter(c=>c.id!==id))

  const handleDeleteHistory = async id => {
    if(!window.confirm('Excluir movimentação?'))return
    try{
      await axios.delete(`/api/movimentacoes/${id}`)
      setHistorico(prev=>prev.filter(m=>m.id!==id))
      toast.success('Movimentação excluída',{autoClose:5000})
    }catch{ toast.error('Erro ao excluir',{autoClose:5000}) }
  }
  const handleEditHistory = async m => {
    const nt = window.prompt('Novo tipo ("entrada" ou "saida"):',m.tipo)
    if(!nt||!['entrada','saida'].includes(nt)){
      toast.error('Tipo inválido',{autoClose:5000}); return
    }
    try{
      await axios.put(`/api/movimentacoes/${m.id}`,{tipo:nt,aluno_id:m.aluno_id})
      setHistorico(prev=>prev.map(x=>x.id===m.id?{...x,tipo:nt}:x))
      toast.success('Movimentação atualizada',{autoClose:5000})
    }catch{toast.error('Erro ao atualizar',{autoClose:5000})}
  }

  // Agrupa caixas
  const caixaCounts = caixas.reduce((acc,c)=>{
    if(!acc[c.id])acc[c.id]={...c,qty:0}
    acc[c.id].qty++ ; return acc
  },{})
  const uniqueCaixas = Object.values(caixaCounts)

  // Estoque atual
  const stockByBox = {}
  historico.forEach(m=>{
    stockByBox[m.caixaNome]=(stockByBox[m.caixaNome]||0)+(m.tipo==='entrada'?1:-1)
  })

  // Timeline
  const steps = [
    { label: 'Operação', info: operation?.toUpperCase(), icon: <Box size={20} /> },
    { label: 'PIN',      info: alunoNome,            icon: <Box size={20} /> },
    { label: 'Controle',  info: '',                   icon: <Box size={20} /> },
    { label: 'Impressão', info: '',                   icon: <Box size={20} /> },
  ]

  return (
    <div className="max-w-4xl mx-auto py-6 px-4">

      {/* TIMELINE no topo-esquerda */}
      <div className="flex items-center space-x-2 mb-6">
        {steps.map((s,i) => (
          <React.Fragment key={i}>
            <div className={`
              flex flex-col items-center text-sm
              ${step-1 === i ? 'text-blue-600 font-bold' : 'text-gray-400'}
            `}>
              {s.icon}
              <span>{s.label}</span>
              {s.info && <span className="text-xs">{s.info}</span>}
            </div>
            {i < steps.length-1 && <div className="flex-1 h-px bg-gray-300" />}
          </React.Fragment>
        ))}
      </div>

      {/* BOTÕES Voltar / Avançar padronizados */}
      <div className="flex justify-between mb-4">
        <button
          onClick={()=>setStep(step-1)}
          disabled={step===1}
          className="px-4 py-2 bg-gray-200 hover:bg-gray-300 rounded disabled:opacity-50"
        >
          &larr; Voltar
        </button>
        {step < 4 && (
          <button
            onClick={()=> setStep(step+1)}
            className="px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded"
          >
            Avançar &rarr;
          </button>
        )}
      </div>

      {/* TELA 1 */}
      {step===1 && (
        <div className="flex gap-8">
          <div
            onClick={()=>{setOperation('entrada');setStep(2)}}
            className="flex-1 cursor-pointer p-8 bg-green-100 hover:bg-green-200 rounded-lg text-center"
          >
            <h3 className="text-lg font-semibold">Entrada</h3>
          </div>
          <div
            onClick={()=>{setOperation('saida');setStep(2)}}
            className="flex-1 cursor-pointer p-8 bg-red-100 hover:bg-red-200 rounded-lg text-center"
          >
            <h3 className="text-lg font-semibold">Saída</h3>
          </div>
        </div>
      )}

      {/* TELA 2 */}
      {step===2 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="text-xl font-bold mb-4">Informe o PIN do aluno</h3>
          <div className="flex gap-4">
            <input
              type="password"
              placeholder="PIN (4 dígitos)"
              value={alunoPin}
              onChange={e=>setAlunoPin(e.target.value.replace(/\D/g,'').slice(0,4))}
              onKeyDown={e=>e.key==='Enter'&&validarPin()}
              className="flex-1 border rounded px-3 py-2"
            />
            <button
              onClick={validarPin}
              className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white px-6 rounded-full"
            >
              Avançar
            </button>
          </div>
        </div>
      )}

      {/* TELA 3 */}
      {step===3 && pinValidated && (
        <>
          {/* Estoque Atual */}
          {Object.keys(stockByBox).length>0 && (
            <div className="bg-white rounded-2xl shadow p-6 mb-6">
              <h3 className="font-medium mb-2">Estoque Atual por Caixa</h3>
              <div className="flex flex-wrap gap-2">
                {Object.entries(stockByBox).map(([nome,qty],i)=>(
                  <div
                    key={nome}
                    className={`px-3 py-1 rounded-full font-semibold ${BADGE_STYLES[i%4]}`}
                  >
                    {nome}: {qty}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Busca/Add */}
          <div className="bg-white rounded-2xl shadow p-6 mb-6">
            <div className="relative flex gap-4">
              <input
                type="text"
                placeholder="Código ou nome da caixa"
                value={codigo}
                onChange={e=>setCodigo(e.target.value)}
                onKeyDown={e=>e.key==='Enter'&&buscarCaixa()}
                className="flex-1 border rounded px-3 py-2"
              />
              <button
                onClick={buscarCaixa}
                className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white px-6 rounded-full"
              >
                Adicionar
              </button>
            </div>
            {suggestions.length>0 && (
              <ul className="absolute z-20 bg-white border rounded shadow mt-12 w-full max-h-40 overflow-y-auto">
                {suggestions.map(c=>(
                  <li
                    key={c.id}
                    onClick={()=>addCaixa(c)}
                    className="px-3 py-2 hover:bg-gray-100 cursor-pointer"
                  >
                    {c.nome} ({c.codigo_barras})
                  </li>
                ))}
              </ul>
            )}
            {uniqueCaixas.length>0 && (
              <div className="flex flex-wrap gap-2 mt-4">
                {uniqueCaixas.map(c=>(
                  <div key={c.id} className="bg-gray-100 px-3 py-1 rounded-full flex items-center">
                    {c.nome} ({c.qty})
                    <button onClick={()=>removerCaixa(c.id)} className="ml-2 text-gray-500">×</button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Histórico */}
          <div className="bg-white rounded-2xl shadow p-6">
            <h3 className="font-bold mb-4">Histórico (últimos 30 dias)</h3>
            <div className="flex gap-4 mb-4">
              <input
                type="text"
                placeholder="Pesquisar..."
                value={searchTerm}
                onChange={e=>setSearchTerm(e.target.value)}
                className="flex-1 border rounded px-3 py-2"
              />
              <button
                onClick={()=>datePickerRef.current.setOpen(true)}
                className="p-2 hover:bg-gray-100 rounded-full"
              >
                <Calendar size={20}/>
              </button>
              <DatePicker
                ref={datePickerRef}
                selected={filterDate?new Date(filterDate):null}
                onChange={d=>setFilterDate(d.toISOString().slice(0,10))}
                customInput={<></>}
                locale="pt-BR" dateFormat="dd/MM/yyyy"
              />
            </div>
            <div className="hidden md:grid grid-cols-6 gap-4 text-sm font-semibold text-gray-600 border-b pb-2 mb-2">
              <div>Caixa</div><div>Tipo</div><div>Aluno</div><div>Operador</div><div>Data</div><div className="text-right">Ações</div>
            </div>
            {(() => {
              const fil = historico.filter(m=>{
                const txt = searchTerm.toLowerCase()
                const okTxt = [m.caixaNome,m.tipo,m.alunoNome,m.operadorNome]
                  .some(f=>f.toLowerCase().includes(txt))
                const okDate = !filterDate || new Date(m.criado_em).toISOString().slice(0,10)===filterDate
                return okTxt && okDate
              })
              if(!fil.length) return <p className="text-gray-500">Nenhuma movimentação.</p>
              return (
                <div className="space-y-4">
                  {fil.map(m=>(
                    <div key={m.id} className="grid grid-cols-1 md:grid-cols-6 gap-4 bg-gray-50 rounded-xl p-4 items-center">
                      <div className="font-medium">{m.caixaNome}</div>
                      <div>{m.tipo}</div>
                      <div>{m.alunoNome}</div>
                      <div>{m.operadorNome}</div>
                      <div>{new Date(m.criado_em).toLocaleString()}</div>
                      <div className="flex justify-end gap-4 items-center">
                        <button
                          onClick={()=>handlePrint({ id:m.caixa_id,nome:m.caixaNome,criado_em:m.criado_em })}
                          className="no-print text-blue-600"
                          title="Reimprimir etiqueta"
                        >
                          <QrCode size={18}/>
                        </button>
                        <Edit2 onClick={()=>handleEditHistory(m)} className="cursor-pointer" size={18}/>
                        <Trash2 onClick={()=>handleDeleteHistory(m.id)} className="cursor-pointer text-red-600" size={18}/>
                      </div>
                    </div>
                  ))}
                </div>
              )
            })()}
          </div>
        </>
      )}

      {/* TELA 4 */}
      {step===4 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="font-bold mb-4">Lista de Impressão de Etiquetas</h3>
          <div className="flex flex-wrap gap-4 mb-6">
            {uniqueCaixas.map(c=>(
              <div key={c.id} className="flex items-center gap-2 bg-gray-50 p-2 rounded-full">
                <span className="font-medium">{c.nome}</span>
                <button
                  onClick={()=>handlePrint(c)}
                  className="no-print flex items-center"
                  title="Imprimir etiqueta"
                >
                  <QrCode size={18}/>
                  {printedBoxes.includes(c.id) && <Check size={18} className="text-green-600 ml-1"/>}
                </button>
              </div>
            ))}
          </div>
          {/* Registrar Entrada/Saída */}
          <button
            onClick={()=>operar(operation)}
            className={`w-full px-6 py-2 rounded-full text-white ${
              operation==='entrada'
                ? 'bg-green-600 hover:bg-green-700'
                : 'bg-red-600 hover:bg-red-700'
            }`}
          >
            Registrar {operation==='entrada'?'Entrada':'Saída'}
          </button>
        </div>
      )}

      {/* Oculto para impressão */}
      {printData && (
        <div id="area-impressao" style={{position:'absolute',left:-10000,top:-10000}}>
          <div className="text-lg font-bold mb-2">{printData.caixaNome}</div>
          <Etiqueta
            ref={componentRef}
            alunoNome={printData.alunoNome}
            caixaId={printData.caixaId}
            criadoEm={printData.criadoEm}
            recebidoPor={printData.recebidoPor}
          />
        </div>
      )}
    </div>
  )
}
